// Convert file to data URL (immediate solution for demo)
export async function uploadToIPFS(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      resolve(reader.result);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

// Create metadata URL (simplified version for demo)
export async function uploadMetadataToIPFS(metadata) {
  // For demo purposes, return a data URL with the metadata
  const metadataString = JSON.stringify(metadata);
  return `data:application/json;base64,${btoa(metadataString)}`;
}
